bad_example:
// Flag argument - function does two things
void render(boolean isSuite) { ... }

// Too many args - belongs in a class
Circle makeCircle(double x, double y, double radius) { ... }

CODE_EXAMPLE:
// Two focused functions instead of one with a flag
void renderForSuite()      { render(suiteSetupPage); }
void renderForSingleTest() { render(setupPage); }

// Parameter object groups related values
Circle makeCircle(Point center, double radius) { ... }

UNIT_TEST_EXAMPLE:
@Test
public void renderForSingleTest_doesNotIncludeSuiteSetup() {
    PageRenderer renderer = new PageRenderer();
    renderer.renderForSingleTest();
    assertFalse(renderer.getOutput().contains("SuiteSetUp"));
}

@Test
public void makeCircle_hasCorrectCenter() {
    Circle c = ShapeFactory.makeCircle(new Point(1, 2), 5.0);
    assertEquals(new Point(1, 2), c.getCenter());
}
